<template>
	<div
		:class="`relative mx-auto flex max-w-fit flex-row items-center justify-center rounded-[1.25rem] font-medium backdrop-blur transition-shadow duration-500 overflow-hidden cursor-pointer ${className}`"
	>
		<div
			v-if="showBorder"
			class="absolute inset-0 bg-cover z-0 pointer-events-none animate-gradient"
			:style="borderStyle"
		>
			<div
				class="absolute inset-0 bg-black rounded-[1.25rem] z-[-1]"
				style="
          width: calc(100% - 2px);
          height: calc(100% - 2px);
          left: 50%;
          top: 50%;
          transform: translate(-50%, -50%);
        "
			/>
		</div>

		<div
			class="inline-block relative z-2 text-transparent bg-cover animate-gradient"
			:style="textStyle"
		>
			{{ text }}
		</div>
	</div>
</template>

<script setup>
import { computed } from "vue";
const props = defineProps({
  text: { type: String, required: true, default: "" },
  className: { type: String, required: false, default: "" },
  colors: { type: Array, required: false, default: () => ["#ffaa40", "#9c40ff", "#ffaa40"] },
  animationSpeed: { type: Number, required: false, default: 8 },
  showBorder: { type: Boolean, required: false, default: false }
});
const gradientStyle = computed(() => ({
  backgroundImage: `linear-gradient(to right, ${props.colors.join(", ")})`,
  animationDuration: `${props.animationSpeed}s`,
  backgroundSize: "300% 100%",
  "--animation-duration": `${props.animationSpeed}s`
}));
const borderStyle = computed(() => ({
  ...gradientStyle.value
}));
const textStyle = computed(() => ({
  ...gradientStyle.value,
  backgroundClip: "text",
  WebkitBackgroundClip: "text"
}));
</script>

<style scoped>
@keyframes gradient{0%{background-position:0 50%}50%{background-position:100% 50%}to{background-position:0 50%}}.animate-gradient{animation:gradient var(--animation-duration,8s) linear infinite}
</style>
